example.code:
{
  "library_version": "1.0.0",
  "archetypes": [
    {
      "archetype": "button",
      "role": "button",
      "name_pattern": "imperative verb phrase",
      "states": [
        "default",
        "hover",
        "active",
        "disabled"
      ],
      "keyboard_map": {
        "Enter": "activate",
        "Space": "activate"
      },
      "focus_behaviour": "visible 2px outline"
    },
    {
      "archetype": "link",
      "role": "link",
      "name_pattern": "destination noun phrase",
      "states": [
        "default",
        "visited",
        "focus"
      ],
      "keyboard_map": {
        "Enter": "activate"
      },
      "focus_behaviour": "underline + outline"
    },
    {
      "archetype": "dialog",
      "role": "dialog",
      "name_pattern": "modal title",
      "states": [
        "open",
        "closed"
      ],
      "keyboard_map": {
        "Esc": "close",
        "Tab": "trap focus"
      },
      "focus_behaviour": "focus first focusable on open; restore on close"
    },
    {
      "archetype": "menu",
      "role": "menu",
      "name_pattern": "menu purpose",
      "states": [
        "collapsed",
        "expanded"
      ],
      "keyboard_map": {
        "ArrowDown": "next item",
        "ArrowUp": "previous",
        "Esc": "close"
      },
      "focus_behaviour": "roving tabindex"
    },
    {
      "archetype": "tabs",
      "role": "tablist",
      "name_pattern": "tab group label",
      "states": [
        "selected",
        "unselected"
      ],
      "keyboard_map": {
        "ArrowRight": "next tab",
        "ArrowLeft": "previous",
        "Home": "first",
        "End": "last"
      },
      "focus_behaviour": "manual or automatic activation"
    },
    {
      "archetype": "combobox",
      "role": "combobox",
      "name_pattern": "field purpose",
      "states": [
        "closed",
        "open",
        "filtering"
      ],
      "keyboard_map": {
        "ArrowDown": "open list",
        "Enter": "select",
        "Esc": "close"
      },
      "focus_behaviour": "aria-activedescendant on listbox option"
    },
    {
      "archetype": "form_field",
      "role": "textbox",
      "name_pattern": "field label",
      "states": [
        "empty",
        "filled",
        "error",
        "disabled"
      ],
      "keyboard_map": {
        "Tab": "next field"
      },
      "focus_behaviour": "visible outline + error message announced via aria-describedby"
    },
    {
      "archetype": "data_table",
      "role": "table",
      "name_pattern": "table caption",
      "states": [
        "sortable",
        "sorted-asc",
        "sorted-desc"
      ],
      "keyboard_map": {
        "ArrowKeys": "cell navigation"
      },
      "focus_behaviour": "cell-by-cell focus, optional row activation"
    }
  ]
}
